class NotificationController {
  create(type: string): Notifier {
    if (type === 'email') return new EmailNotifier();
    if (type === 'sms') return new SmsNotifier();
    if (type === 'push') return new PushNotifier();
    throw new Error('Unknown notifier type');
  }
}

class ParserEngine {
  parse(kind: string, input: string): Ast {
    if (kind === 'json') return new JsonParser().parse(input);
    if (kind === 'yaml') return new YamlParser().parse(input);
    if (kind === 'toml') return new TomlParser().parse(input);
    throw new Error('Unsupported parser');
  }
}

