class ExportService {
  export(type: string, data: Data): string {
    if (type === 'csv') return new CsvExporter().export(data);
    if (type === 'json') return new JsonExporter().export(data);
    return new XmlExporter().export(data);
  }
}
// Version B
abstract class ExportService {
  export(data: Data): string { return this.createExporter().export(data); }
  protected abstract createExporter(): Exporter;
}
